//           ✦ TYPESCRIPT NOTES ✦
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

// ◈ WHY TYPESCRIPT OVER JAVASCRIPT?
//   → catches errors before running the code
//   → better autocomplete & IDE support
//   → types act as documentation
//   → compiles down to plain JS

// ◈ SETUP
//   npm install -g typescript     (install)
//   tsc first.ts && node first.js (compile & run)
//   npx ts-node first.ts          (shortcut)


// ── TYPE ANNOTATION ──────────────────────
// manually tell TS the type

// let variable1 : number  = 12
// let variable2 : string  = "hello"
// let variable3 : boolean = true
// let variable4 : any     = "anything"   // ⚠️ avoid


// ── TYPE INFERENCE ───────────────────────
// TS figures out the type on its own

// let x = 1234     // inferred: number
// x = "hello"      // ❌ error


// ── ARRAYS ───────────────────────────────

// let nums : number[] = []
// let strs : string[] = []


// ── OBJECTS ──────────────────────────────
// '?' means the property is optional

// let variable10 : {
//     name: string,
//     age?: number,       // optional
//     isStudent: boolean
// }


// ── FUNCTIONS ────────────────────────────
// annotate params and return type

// function sum(n1: number, n2: number): number {
//     return n1 + n2
// }


// ── FUNCTION OVERLOADING ─────────────────
// same name, different signatures

// function sum(n1: number, n2: number): number
// function sum(n1: string, n2: string): string

// function definition

// function sum(n1: any,    n2: any   ): any {
//  return n1 + n2 
// }

// function calling 
// sum(1, 2)
// sum("1", "2")
// sum("1", 2) --  not possible as it does not follow any signature


// ── REST PARAMETERS ──────────────────────
// '...param' collects extra args into an array

function addition(a: number, ...param: number[]) {
    let sum = 0
    for (let i = 0; i < param.length; i++) {
        sum += param[i]
    }
    console.log(sum)
}

addition(1, 2, 23, 5, 7, 32, 23, 34, 34, 34)
// a = 1 | param = [2,23,5,7,32,23,34,34,34] → 194